const b = $input.first().json.body || $input.first().json;
const seed = (b.seed_post||'').trim();
if (seed.length < 30) return [{ json: { error: 'seed_post required min 30 chars' } }];
const statuses = Array.isArray(b.status_filter) && b.status_filter.length ? b.status_filter : ['active','warming'];
const langs = Array.isArray(b.langs) ? b.langs : [];
const dry = b.dry_run === true;
return [{ json: { seed, statuses, langs, dry } }];

const base = $('Validate base').first().json;
if (base.error) return [{ json: base }];
const all = $input.all().map(i => i.json).filter(r => r && r.id);
const chans = all.filter(r => base.statuses.includes(r.status) && (!base.langs.length || base.langs.includes(r.lang)));
const needLangs = [...new Set(chans.map(c => c.lang).filter(l => l !== 'en'))];
return [{ json: { seed: base.seed, dry: base.dry, channels: chans, needLangs, hasTr: needLangs.length > 0 } }];

