const plan = $('Plan').first().json;
let tr = {};
try {
  const items = $input.all();
  let resp = items.length ? items[0].json : {};
  if (resp && resp.body) resp = resp.body;
  let raw = (resp && (resp.response || resp.translations)) || '';
  if (typeof raw === 'object') { tr = raw; }
  else if (typeof raw === 'string' && raw.trim()) {
    let s = raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```\s*$/i,'').trim();
    const a = s.indexOf('{'), b = s.lastIndexOf('}');
    if (a >= 0 && b > a) s = s.slice(a, b + 1);
    try { tr = JSON.parse(s); } catch (e) { tr = {}; }
  }
} catch (e) {}
function brandSanitize(s){ if(!s||typeof s!=='string') return s; const MAP=[['You ?Tube','video platforms'],['Google','search engines'],['Facebook','social media'],['Instagram','social media'],['TikTok','social media'],['Twitch','live streaming platforms'],['Twitter','social media'],['LinkedIn','professional networks'],['Amazon','e-commerce sites'],['GitHub','code platforms']]; let o=s; for(let i=0;i<MAP.length;i++){ o=o.replace(new RegExp('\\b'+MAP[i][0]+'\\b','gi'),MAP[i][1]); } return o.replace(/[ \t]{2,}/g,' ').trim(); }
function langFix(lang,s){ if(!s) return s; const M={ it:[['spiacciono','spiano'],['ti spiace','ti spia'],['spiace in segreto','spia in segreto']], es:[['te espien','te espían'],['espien','espían'],['te espie','te espía'],['los bloca','los bloquea'],['las bloca','las bloquea'],['bloca','bloquea']], pt:[['te espião','te espiona']] }; const arr=M[lang]||[]; let o=s; for(let i=0;i<arr.length;i++){ o=o.replace(new RegExp('\\b'+arr[i][0]+'\\b','gi'),arr[i][1]); } return o; }
const out = [];
for (const c of plan.channels) {
  let raw = c.lang === 'en' ? plan.seed : (tr[c.lang] || '');
  let body = brandSanitize(String(raw||'').replace(/^\"|\"$/g,'').trim());
  body = langFix(c.lang, body);
  const brand_leak = /\b(you ?tube|facebook|instagram|tiktok|twitch|google)\b/i.test(body);
  const generation_failed = body.length < 20;
  out.push({ json: { platform:c.platform, channel:c.channel, lang:c.lang, account_id:c.account_id, body, brand_leak, generation_failed, dry: plan.dry } });
}
if (!out.length) return [{ json: { error:'no channels', _empty:true } }];
return out;

const ins = $input.all().map(i=>i.json).filter(x=>x && x.id);
const proc = $('Assemble per channel').all().map(i=>i.json).filter(p=>!p._empty);
const skipped = proc.filter(p=>p.brand_leak || p.generation_failed).map(p=>({lang:p.lang, ch:p.channel, reason: p.generation_failed?'gen_failed':'brand_leak'}));
return [{ json: { ok:true, channels_processed: proc.length, rows_inserted: ins.length, skipped, sample: proc.slice(0,8).map(p=>({lang:p.lang, ch:p.channel, body:String(p.body).slice(0,130)})) } }];
